var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이야압!!","JPN":"やああっ！！","ENG":"Eeyaah!","TWN":"看招～～！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇게 무작정 덤벼들면 상대가 발만 걸어도 넘어질걸. ","JPN":"そうやって無鉄砲に飛びかかると、相手が足をかけるだけで転ぶよ。 ","ENG":"Your opponent can easily make you trip and fall if you charge in like that.","TWN":"你這樣一股腦兒地衝上來，對方只要伸出腳就能絆倒你。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이렇게.","JPN":"こんな風に。","ENG":"Just like this.","TWN":"就像這樣。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"흐냑!?","JPN":"ふにゃっ！？","ENG":"Huah?!","TWN":"哎呀！？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 꼬맹아! 건틀렛 포기하고 코미디언 지망하냐?","JPN":"おい、おこちゃま！　ガントレットは諦めてお笑い芸人でも目指す気か？","ENG":"Hey, kid! Did you switch tracks to become a comedian?","TWN":"喂，小鬼！你要放棄聖鎧，改行當喜劇演員嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"시끄러워요! 그러는 라이카도 한 발도 못 맞췄으면서!","JPN":"うるさいわよ！　そういうライカも一発も当てられなかったくせに！","ENG":"Shut it! What about you, Laika?! You also couldn't hit her once!","TWN":"你閉嘴，萊卡！你明明也一發都沒射中！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너 말 다했냐? 가뜩이나 페인트탄이라 탄속도 느려서 죽을 맛인데!","JPN":"言うことはそれだけか？　ただでさえペイント弾だから弾速も遅くて大変だってのに！","ENG":"You done? I'm having a bad day as it is with these slow paintballs!","TWN":"你說夠沒有？這裡面裝的就是漆彈，彈速慢得要命！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다 안 했어요! 어른들은 항상 그렇게 핑계 투성이죠!","JPN":"まだあるわよ！　大人はいつもそうやって言い訳ばっかり！","ENG":"No, I'm not done! Adults are always coming up with excuses!","TWN":"我還沒說夠！大人就是喜歡找各種藉口！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"나이 몇 살 먹은 것 갖고 으스대지 말아요! 늘어난 건 주름살뿐이면서!","JPN":"ちょっとばかり年上だからって偉ぶらないでほしいわ！　増えたのはシワだけのくせに！","ENG":"Don't think you're better than me just because you're a bit older! All you have more than me are wrinkles!","TWN":"大我幾歲有什麼了不起的！不過就是皺紋比我多而已！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저게 진짜…… 너 앞통수보다 뒤통수에 먼저 총알 구멍 나고 싶냐?","JPN":"言わせておけば……後頭部に風穴開けてやろうか？","ENG":"Why you little... Do you want a bullet hole made in the back of your head?","TWN":"你……真是的，你是想吃子彈是不是？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어린애가 말버릇이 대체 왜 저래……? 설마 소대장처럼 몸만 어린애인가?","JPN":"子どものくせにあの言葉遣いって……まさか小隊長みたいに、身体だけが子どもなの？","ENG":"What's with this girl's attitude...? Wait, could she be like Commander? Someone who just looks young?","TWN":"這麼毒舌的小孩……？還是她和小隊長一樣，只是長得矮？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"굉장해요, 미나 선배! 무기도 없이 두 명을 동시에 상대하다니!","JPN":"すごいです、ミナ先輩！　武器もないのに二人を同時に相手するなんて！","ENG":"You're so amazing, Mina! Taking on two of them at once even without a weapon!","TWN":"真厲害，米娜前輩！連武器都不用，就能同時對付二個人！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘? 벌써 움직여도 돼?","JPN":"ノエル？　もう動いても大丈夫なの？","ENG":"Noelle? Are you sure you're fit to move around already?","TWN":"洛艾兒？你可以動了嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어떻게 누워 있어요. 미나 선배 활약상을 직접 볼 수 있는 기회인데.","JPN":"寝ていられるわけないじゃないですか！　ミナ先輩の活躍を直接見られるチャンスなのに！","ENG":"How can I stay lying down? It's my chance to see you in action up close!","TWN":"我怎麼能躺著呢，這可是能親眼目睹米娜前輩英姿的好機會。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"역시 펜릴 소대 에이스다운 활약! 멋져요!","JPN":"やっぱりフェンリル小隊のエースらしい活躍！　素敵です！","ENG":"Just as I expected! The ace of Fenrir Squad! So cool!","TWN":"不愧是芬里爾小隊的王牌！太帥啦！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"호들갑 떨 것 없어.","JPN":"大げさだな。","ENG":"There's no need to make a fuss about it.","TWN":"少在那邊大驚小怪的。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"예전에 마주쳤던 상대들이랑 비교하면 이 사람들은 그냥 그렇거든.","JPN":"以前戦った相手に比べたら、この人たちは大したことないから。","ENG":"These two are nothing compared to what I've faced before.","TWN":"和以前遇到的對手相比，這些人根本不算什麼。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"특히 저 애는 더. 실전 경험이 부족해.","JPN":"特にあの子。実戦の経験が足りない。","ENG":"Especially that little girl. She seems to have no experience at all.","TWN":"尤其是那孩子，太缺乏實戰經驗。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇다잖아, 꼬맹아. 분발 좀 해.","JPN":"だとさ、おこちゃま。踏ん張れよ。","ENG":"Did you hear what she said about you, kid? You gotta keep it up.","TWN":"她說我們根本不算什麼欸！小鬼，再多加把勁。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"펜릴 소대……?","JPN":"フェンリル小隊……？","ENG":"Fenrir Squad...?","TWN":"芬里爾小隊……？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"맞아. 그러고 보니 영상에서 본 얼굴이랑 닮았어.","JPN":"本当だわ。そういえば、動画で見た顔と似てる。","ENG":"Oh, right. She looks similar to the face I once saw on a video.","TWN":"沒錯，這麼看來，她的臉長得和影片裡看到的人很像。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼 정말 여기가 그 코핀 컴퍼니라고? 왜 이런 곳에…….     ","JPN":"じゃあ、本当にここがあのコフィンカンパニー？　どうしてこんなところに……     ","ENG":"Wait, then this really is Coffin Company? Why are they even here...?","TWN":"那這裡真的是科芬公司嗎？為什麼會在這種地方……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 갑자기 왜 혼자 중얼거려? 넘어질 때 어디 잘못 부딪쳤어?","JPN":"おい、なに急に一人でぶつぶつ言ってるんだよ？　転んだ拍子にどっかぶつけたのか？","ENG":"Hey, what are you mumbling about? Did you hurt your head when you fell?","TWN":"喂，你突然在自言自語什麼？摔到腦袋啦？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카. 실탄 장전해요.","JPN":"ライカ。実弾装填して。","ENG":"Laika. Switch to live ammunition.","TWN":"萊卡，裝填實彈。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"실탄이라고?","JPN":"実弾？","ENG":"Live ammunition?","TWN":"實彈？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너 미쳤냐? 그러다 누구 죽으면 어떻게 책임지게?","JPN":"正気かよ？　それで誰か死んだらどうやって責任持つ気なんだよ。","ENG":"Are you crazy?! Who's gonna be responsible if someone dies here?","TWN":"你瘋啦？萬一出人命的話怎麼辦？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"호라이즌 때 했던 소릴 또 해야겠어요?","JPN":"ホライズンの時した話、また聞きたいの？","ENG":"Do I have to repeat what I said to you when we met Horizon?","TWN":"對付地平線的時候，你忘記我說過什麼嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제 기억이 맞다면, 저 언니는 A급 이상으로 평가 받는 카운터예요. ","JPN":"私の記憶が正しければ、あの人は評価がAランク以上のカウンターよ。 ","ENG":"If I remember correctly, that person is considered to be a Grade A Counter.","TWN":"如果我沒記錯，那個姊姊是A級以上的制裁者。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그런 사람이랑 싸워 볼 기회가 어디 흔한 줄 알아요?","JPN":"そんな人と戦えるチャンスなんて滅多にないわ。","ENG":"Can't you see that an opportunity to fight someone like this doesn't come around that often?","TWN":"你以為和這種人交手的機會多嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"당연히 안 흔하지! 이 미치광이야!","JPN":"なくて当たり前だ！　このサイコが！","ENG":"Of course it's a rare opportunity, you lunatic!","TWN":"當然不多！你這個瘋子！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"A급 카운터한테 누가 맨몸으로 덤벼? 자살 지망생이 그렇게 많은 줄 알아? ","JPN":"Aランクのカウンターに丸腰で飛びかかるやつがどこにいる？　そんなにたくさん自殺希望者がいるわけないだろ！ ","ENG":"But who fights a Grade A Counter without preparation? There aren't a lot of people who aspire suicide, you know.","TWN":"誰會手無寸鐵地和A級制裁者交手？你以為大家都想自殺嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"누가 A급이야. B급 구실이나 겨우 하는 거겠지.","JPN":"誰がAランクだって？　Bランクもぎりぎりだけど。","ENG":"Who says anything about me being a Grade A? I barely make the cutline for a Grade B.","TWN":"我沒到A級那麼厲害，勉強算B級吧。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"숨 쉬듯이 자연스럽게 상대를 도발하는 미나 선배…! 정말 무시무시해요!","JPN":"まるで息をするように自然に相手を挑発するミナ先輩……！　本当に恐ろしいです！","ENG":"Look how naturally Mina taunts her opponents...! So intimidating!","TWN":"像呼吸一樣自然地挑釁對手的米娜前輩……！真是太厲害啦！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응…? 내가 뭐 이상한 말 했어?","JPN":"うん……？　私、なんか変なことでも言った？","ENG":"Hmm...? Did I say something weird?","TWN":"呃……？我有說錯話嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"좋아요. 라이카가 돕지 않겠다면 저 혼자서라도 싸우겠어요.","JPN":"もういい。ライカが手伝わないなら、私一人ででも戦うわ。","ENG":"All right. If you're not gonna help, Laika, I'll fight her on my own.","TWN":"好。萊卡不想幫忙的話，那就我一個人來。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"고등급 카운터라면 실탄은 어차피 안 무섭겠죠?","JPN":"高ランクのカウンターなら、どうせ実弾なんて怖くないわよね？","ENG":"A high-grade Counter like yourself aren't afraid of some bullets, right?","TWN":"如果是高階的制裁者，應該也不會害怕實彈吧？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그걸 쏘는 순간 나도 더 이상 봐주지 않을 거야.","JPN":"それを撃ったら最後、私ももう手加減しないよ。","ENG":"You fire that at me, I won't hold back anymore.","TWN":"你射出實彈的瞬間，我也不會再對你手下留情。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나랑 노엘은 괜찮을지 몰라도, 우리 사장님은 아니거든.","JPN":"私とノエルは大丈夫かもしれないけど、社長は違うから。","ENG":"Noelle and I might be fine, but not Boss.","TWN":"我和洛艾兒或許沒事，但我們老闆是普通人。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도 도와 드릴게요! 펜릴 소대의 일원으로서 계속 구경만 할 수는 없어요!","JPN":"私も手伝います！　フェンリル小隊の一員として、ずっと見てばかりもいられません！","ENG":"I'll help out too! As an official member of Fenrir Squad, I can't just stand on the sidelines!","TWN":"我也來幫忙！作為芬里爾小隊的一員，我不能一直看熱鬧！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그리고 헬멧에 맞은 자리가 아직도 얼얼하다구요…. 이대로 혹이 안 가라앉으면 어떡하죠….","JPN":"それに、ヘルメットに当たったところがまだ痛いですし……このままたんこぶが消えなかったらどうしましょう……","ENG":"Also, my head still hurts from getting whacked by that helmet... What if the bump doesn't heal...?","TWN":"而且我剛才被頭盔砸到的地方還是腫腫的……如果腫塊消不下去怎麼辦……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…넌 그냥 좀 쉬고 있어.","JPN":"……あなたはちょっと休んでて。","ENG":"...You just rest for now.","TWN":"……你就在旁邊休息吧。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"바라던 바네요. 진지하게 싸워 주세요.","JPN":"望むところです。真剣に戦ってください。","ENG":"Now we're talking. Bring it on.","TWN":"正合我意，請認真與我交手。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제가 노리는 건 겨우 A급이 아니거든요.","JPN":"私が狙ってるのは、たかがAランク程度じゃありませんから。","ENG":"What I'm aiming for is not just a Grade A Counter.","TWN":"因為我的目標不僅僅是A級。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀…"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"에라, 모르겠다. 한 번 혼쭐이 나 봐야 정신을 차리지.","JPN":"もう、なるようになれ。一度痛い目に遭った方がいい。","ENG":"Ugh, whatever. Guess you'll snap back to your senses the hard way.","TWN":"隨便你吧，你就是那種不到黃河心不死的類型。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"나 왔어, 얘들아~","JPN":"ただいま、二人とも～","ENG":"Gals, I'm back!","TWN":"大家，我來囉～"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"어휴, 이게 웬 먼지야? 또 싸운 거면 나 진짜 그만둔다?","JPN":"うわ、何？　この埃。またケンカするなら、私本当にもう辞めるからね？","ENG":"Whoa, what's with all the dust? I'm gonna quit if you two fight again, all right?","TWN":"咳，怎麼這麼多灰塵？又打架的話，我就真的走人囉？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……앗.","JPN":"……あっ。","ENG":"...Ah.","TWN":"……呃。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"스, 스키너? 왜 이렇게 빨리 왔어?","JPN":"す、スキナー？　なんでこんなに早く帰ってきたんだ？","ENG":"S-Skinner? Why did you come so early?","TWN":"史，史金納？你怎麼這麼快就來啦？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"예전 거래처에서 원래 쓰던 드론을 싸게 내놓는다잖아.","JPN":"昔の取引先が、元々使ってたドローンを安く売るって言うのよ。","ENG":"Because an old client of mine is selling their used drones for cheap.","TWN":"以前的客戶說要低價出售二手的無人機。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"먼저 사는 사람이 임자인 가격이더라. 금방 다녀올게.","JPN":"早い者勝ちの値段なんだって。さっそく行ってくるわね。","ENG":"It's first come, first served. I gotta go quick.","TWN":"先搶先贏嘛，所以我當然要抓緊時間啦。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 여기 펠리세트가 부탁한 몸 튼튼 마음 튼튼 영양 젤리랑….","JPN":"はい、フェリセットに頼まれてた心身ともに元気になる栄養ジェリーと……","ENG":"Here you go. The strong body and mind jellies you asked for, Félicette.","TWN":"拿去，這個是費莉塞特要的強身健心營養軟糖……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 당신들은? 와일러가 보냈어?","JPN":"な、何？　あなたたち。ワイラーに送り込まれたの？","ENG":"H-huh? Who are you? Did Wyler send you?","TWN":"怎，怎麼回事？你們是誰？是瓦勒派你們來的嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"집주인일세.","JPN":"ここの所有者なんだが。","ENG":"I'm the owner of this place.","TWN":"我們是這裡的屋主。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};